     ((equiv_loops_image_subproof A B f x
       :
       fmap loops f x = fmap loops (h $o g) x) @
      fmap_comp loops g h x)^)
    :
    (fun x : loops A => fmap loops h (fmap loops g x)) == fmap loops f;
  inclass1 := conn_map_fmap_loops A C g;
